using Microsoft.AspNetCore.Mvc;
using System.Security.Claims;

namespace InvoiceManagementAPI.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class InvoicesController : ControllerBase
    {
        // Assuming you have an InvoiceService to fetch the invoice details based on id
        private readonly IInvoiceService _invoiceService; 

        public InvoicesController(IInvoiceService invoiceService)
        {
            _invoiceService = invoiceService;
        }
        
        [HttpGet("{id}")]
        public async Task<IActionResult> GetInvoiceDetails([FromRoute] string id)
        {
            // Assuming the user's name can be found in User.Identity (based on your authentication middleware implementation). 
            var username = HttpContext.User.Identity.Name;  
            
            if (!int.TryParse(id, out int invoiceId))
            {
                return BadRequest("Invalid Invoice Id");
            }

            // Call the service to get invoice details using id 
            var result = await _invoiceService.GetInvoiceDetailsAsync(username, invoiceId);  
            
            if (result == null)
            {
                return NotFound();    // Invoice not found
            }
            
            return Ok(result);        // Return the details of the invoice
        } 
    }    
